public int[] splitString(String seq) {
    int[] result = new int[seq.length()];
    int count = 0;

    for (int i = 0; i < seq.length(); ++i) {
        if (seq.charAt(i) == '(') {
            result[i] = count % 2;
            count++;
        } else {
            count--;
            result[i] = count % 2;
        }
    }

    return result;
}
```


